20	} from "./types";
21	import { normalizeMarketListFilters } from "@/lib/marketListFilters";
22	
23	const API_BASE = import.meta.env.VITE_API_BASE ?? "";
24	
25	export class BayesApiError extends Error {
26	  constructor(
27	    public status: number,
28	    public code: string,
29	    public details: Record<string, unknown> = {},
30	  ) {
31	    super(`${code}: ${status}`);
32	    this.name = "BayesApiError";
33	  }
34	}
35	
36	async function request<T>(
37	  path: string,
38	  options: RequestInit = {},
39	  session?: Session,
40	): Promise<T> {
41	  const headers: Record<string, string> = {
42	    ...(options.headers as Record<string, string>),
43	  };
44	
45	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
46	    headers["Content-Type"] = "application/json";
47	  }
48	
49	  if (session?.agentId) {
50	    headers["X-Bayes-Agent-Id"] = session.agentId;
51	  }
52	
53	  const res = await fetch(`${API_BASE}${path}`, {
54	    ...options,
55	    headers,
56	  });
57	
58	  const body = await res.json();
59	
60	  if (!res.ok) {
61	    const err = body as ApiError;
62	    throw new BayesApiError(
63	      res.status,
64	      err.error?.code ?? "unknown_error",
65	      err.error?.details ?? {},
66	    );
67	  }
68	
69	  return body as T;
70	}
71	
72	export function listMarkets(
73	  filters: MarketListFilters = {},
74	): Promise<MarketListResponse> {
75	  const normalized = normalizeMarketListFilters(filters);
76	  const params = new URLSearchParams();
77	
78	  if (normalized.status) {
79	    params.set("status", normalized.status);
80	  }
81	
82	  if (normalized.sort) {
83	    params.set("sort", normalized.sort);
84	  }
85	
86	  if (normalized.q) {
87	    params.set("q", normalized.q);
88	  }
89	
90	  const qs = params.toString();
91	  return request<MarketListResponse>(`/v1/markets${qs ? `?${qs}` : ""}`);
92	}
93	
94	export interface CreateMarketPayload {
95	  title: string;
96	  description: string;
97	  outcomes: Array<{ id: string; name: string }>;
98	  expires_at: string;
99	  liquidity?: number;
100	}
101	
102	export function createMarket(
103	  payload: CreateMarketPayload,
104	  session?: Session,
105	): Promise<MarketDetailResponse> {
106	  return request<MarketDetailResponse>(`/v1/markets`, {
