92	              </g>
93	            );
94	          })}
95	
96	          {xTicks.map((tick) => {
97	            const x = scaleNumber(tick, domainStart, domainEnd, chartLeft, chartRight);
98	            return (
99	              <g key={tick}>
100	                <line
101	                  x1={x}
102	                  y1={chartTop}
103	                  x2={x}
104	                  y2={chartBottom}
105	                  stroke="rgba(139, 143, 163, 0.16)"
106	                />
107	                <text
108	                  x={x}
109	                  y={HEIGHT - 14}
110	                  fill="var(--color-text-muted)"
111	                  fontSize="11"
112	                  textAnchor="middle"
113	                >
114	                  {formatTimestampLabel(new Date(tick).toISOString(), interval)}
115	                </text>
116	              </g>
117	            );
118	          })}
119	
120	          <line
121	            x1={chartLeft}
122	            y1={chartBottom}
123	            x2={chartRight}
124	            y2={chartBottom}
125	            stroke="var(--color-border)"
126	          />
127	          <line
128	            x1={chartLeft}
129	            y1={chartTop}
130	            x2={chartLeft}
131	            y2={chartBottom}
132	            stroke="var(--color-border)"
133	          />
134	
135	          {series.map((outcome, outcomeIndex) => {
136	            const points = outcome.points.map((point) => ({
137	              x: scaleNumber(
138	                Date.parse(point.emittedAt),
139	                domainStart,
140	                domainEnd,
141	                chartLeft,
